import{_ as e,o as d,c as r,a2 as i}from"./chunks/framework.BZO4qERu.js";const p=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"rudder/04-参考/FAQ.md","filePath":"rudder/04-参考/FAQ.md"}'),s={name:"rudder/04-参考/FAQ.md"};function l(t,a,o,n,h,c){return d(),r("div",null,[...a[0]||(a[0]=[i(`<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="这玩意儿跟-claude-md-agents-md-cursorrules-有啥区别" tabindex="-1">这玩意儿跟 CLAUDE.md / AGENTS.md / .cursorrules 有啥区别？ <a class="header-anchor" href="#这玩意儿跟-claude-md-agents-md-cursorrules-有啥区别" aria-label="Permalink to &quot;这玩意儿跟 CLAUDE.md / AGENTS.md / .cursorrules 有啥区别？&quot;">​</a></h2><p>这些文件确实有用，但用久了都会变成几千行的缝合怪。Rudder 做了分层：规范按作用域拆分、任务有独立 PRD、工作流有关卡控制、跨平台自动适配。一句话：<strong>不把所有东西塞进一个文件里。</strong></p><h2 id="rudder-是不是只支持-claude-code" tabindex="-1">Rudder 是不是只支持 Claude Code？ <a class="header-anchor" href="#rudder-是不是只支持-claude-code" aria-label="Permalink to &quot;Rudder 是不是只支持 Claude Code？&quot;">​</a></h2><p>不是。Rudder 是项目层的基础设施，14 个 AI coding 平台都能用。你可以今天用 Gemini 写前端，明天切 Claude Code 写后端，后天让 Codex 审查。</p><h2 id="适合一个人用还是团队" tabindex="-1">适合一个人用还是团队？ <a class="header-anchor" href="#适合一个人用还是团队" aria-label="Permalink to &quot;适合一个人用还是团队？&quot;">​</a></h2><p>都行。一个人用主要是项目记忆 + 可复用流程；团队用收益更大——标准统一、任务边界清晰、上下文可审查，换平台不换脑子。</p><h2 id="spec-文件是不是得手动一个一个写" tabindex="-1">Spec 文件是不是得手动一个一个写？ <a class="header-anchor" href="#spec-文件是不是得手动一个一个写" aria-label="Permalink to &quot;Spec 文件是不是得手动一个一个写？&quot;">​</a></h2><p>不用。大多数团队的做法是让 AI 先基于现有代码生成初稿，然后人工收紧关键规则。Rudder 还内置了 <code>rudder-spec-bootstarp</code> skill，可以自动分析代码库生成 Spec。核心思想是：把高价值的规则显式化、版本化，剩下的让 AI 自己搞定。</p><h2 id="团队协作会不会经常冲突" tabindex="-1">团队协作会不会经常冲突？ <a class="header-anchor" href="#团队协作会不会经常冲突" aria-label="Permalink to &quot;团队协作会不会经常冲突？&quot;">​</a></h2><p>不会。个人工作区的 journal 是每个开发者独立维护的，共享的 Spec 和任务进仓库走 git——跟其他项目代码一样，冲突就合并不就完了。</p><h2 id="config-local-yml-是什么" tabindex="-1">config_local.yml 是什么？ <a class="header-anchor" href="#config-local-yml-是什么" aria-label="Permalink to &quot;config_local.yml 是什么？&quot;">​</a></h2><p>团队共享的 <code>config.yaml</code> 声明需要什么工具和版本；个人的 <code>config_local.yml</code> 声明工具的实际路径。AI 在对话中发现新工具时会自动补充到 <code>config_local.yml</code>，越用越好用。</p><h2 id="工具路径不对怎么办" tabindex="-1">工具路径不对怎么办？ <a class="header-anchor" href="#工具路径不对怎么办" aria-label="Permalink to &quot;工具路径不对怎么办？&quot;">​</a></h2><p>找到正确路径后手动更新 <code>.rudder/config_local.yml</code>，比如 <code>which mvn</code> 或 <code>where java</code>。后续 session 就能直接用了。</p><h2 id="更新-rudder-后项目怎么同步" tabindex="-1">更新 Rudder 后项目怎么同步？ <a class="header-anchor" href="#更新-rudder-后项目怎么同步" aria-label="Permalink to &quot;更新 Rudder 后项目怎么同步？&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#FFCB6B;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#C3E88D;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#C3E88D;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#C3E88D;"> @mengde1231/rudder@latest</span><span style="--shiki-light:#6A737D;--shiki-light-font-style:inherit;--shiki-dark:#676E95;--shiki-dark-font-style:italic;">  # 更新 CLI</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#FFCB6B;">rudder</span><span style="--shiki-light:#032F62;--shiki-dark:#C3E88D;"> update</span><span style="--shiki-light:#6A737D;--shiki-light-font-style:inherit;--shiki-dark:#676E95;--shiki-dark-font-style:italic;">                              # 更新项目配置</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="rudder-会修改我的源代码吗" tabindex="-1">Rudder 会修改我的源代码吗？ <a class="header-anchor" href="#rudder-会修改我的源代码吗" aria-label="Permalink to &quot;Rudder 会修改我的源代码吗？&quot;">​</a></h2><p>不会。Rudder 只管理 <code>.rudder/</code> 和平台配置目录（<code>.claude/</code>、<code>.cursor/</code> 等）。代码变更完全由 AI 和你自己控制。</p><h2 id="支持-python-项目吗-java-呢" tabindex="-1">支持 Python 项目吗？Java 呢？ <a class="header-anchor" href="#支持-python-项目吗-java-呢" aria-label="Permalink to &quot;支持 Python 项目吗？Java 呢？&quot;">​</a></h2><p>完全支持。Rudder 本身是平台无关的。作者作为 Java 全栈开发日常自用，Java Spec 模板最丰富，但其他语言同样兼容。</p><h2 id="版本为什么从-0-5-30-开始" tabindex="-1">版本为什么从 0.5.30 开始？ <a class="header-anchor" href="#版本为什么从-0-5-30-开始" aria-label="Permalink to &quot;版本为什么从 0.5.30 开始？&quot;">​</a></h2><p>Rudder 诞生于 5 月，主版本用了 0.5。之前本地迭代了很多版本，0.5.30 是第一个公开发布版本。</p><h2 id="在线文档什么时候上线" tabindex="-1">在线文档什么时候上线？ <a class="header-anchor" href="#在线文档什么时候上线" aria-label="Permalink to &quot;在线文档什么时候上线？&quot;">​</a></h2><p>Rudder 在线文档和使用手册正在逐步完善中，敬请期待。</p>`,25)])])}const m=e(s,[["render",l]]);export{p as __pageData,m as default};
